// src/design/linkHomeDesign.js
export const linkHomeDesign = {
  // Layout & containers
  pageWrapper: "min-h-screen bg-slate-50/70 px-4 sm:px-6 lg:px-10 py-8 md:py-12",
  container: "max-w-5xl mx-auto",

  // Header
  headerWrapper: "flex flex-col sm:flex-row sm:items-center sm:justify-between gap-5 mb-10 md:mb-12",
  title: "text-3xl sm:text-4xl font-bold tracking-tight text-slate-900",
  subtitle: "mt-1.5 text-sm sm:text-base text-slate-500 font-medium",

  // Card
  card: "bg-white rounded-2xl border border-slate-200/70 shadow-sm overflow-hidden",

  // Form area
  formSection: "p-6 md:p-7 border-b border-slate-200/70",
  form: "flex flex-col sm:flex-row gap-4",
  input: 
    "w-full bg-white border border-slate-300 focus:border-indigo-500/70 " +
    "focus:ring-4 focus:ring-indigo-100 rounded-xl px-5 py-3.5 text-sm " +
    "placeholder:text-slate-400 transition-all duration-200 outline-none",
  buttonPrimary:
    "inline-flex items-center justify-center gap-2.5 " +
    "bg-gradient-to-b from-indigo-600 to-indigo-700 hover:from-indigo-600 hover:to-indigo-800 " +
    "active:from-indigo-700 active:to-indigo-800 " +
    "text-white px-6 py-3.5 rounded-xl text-sm font-semibold shadow-md " +
    "hover:shadow-lg active:shadow-sm transition-all duration-200 min-w-[140px]",

  // Table / List
  listWrapper: "divide-y divide-slate-100",

  // Desktop header (hidden on mobile)
  tableHeader:
    "hidden md:grid md:grid-cols-[1fr_auto] px-7 py-4 text-xs font-semibold uppercase tracking-wider text-slate-500 bg-slate-50/70",

  // Row (both mobile + desktop)
  row: 
    "grid grid-cols-1 md:grid-cols-[1fr_auto] items-center " +
    "px-6 py-5 md:px-7 md:py-5 hover:bg-slate-50/80 transition-colors duration-150",

  // Mobile name + badge line
  mobileNameArea: "flex items-center justify-between gap-4",
  nameAndBadge: "flex items-center gap-3.5",
  nameText: "font-medium text-slate-800 text-[15px]",
  badge:
    "inline-flex items-center px-3 py-1 rounded-full text-xs font-semibold " +
    "bg-emerald-100/80 text-emerald-700 border border-emerald-200/70",

  // Actions
  actionsMobile: "flex items-center gap-5 md:hidden",
  actionsDesktop: "hidden md:flex items-center gap-6",

  actionButton:
    "p-2 -m-2 rounded-lg text-slate-500 hover:text-indigo-700 hover:bg-indigo-50/60 " +
    "active:text-indigo-800 transition-colors duration-150",

  // Empty state
  emptyState:
    "py-24 md:py-32 text-center text-slate-400/80 text-sm sm:text-base font-medium",

  // Animation variants (optional – you can use these directly)
  itemVariants: {
    hidden: { opacity: 0, y: 12 },
    visible: { opacity: 1, y: 0 },
    exit: { opacity: 0, x: -30, transition: { duration: 0.18 } },
  },
};
